// Copyright 2020 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.package gocommandimport ("bytes""context""fmt""os""path/filepath""regexp""strings""time""golang.org/x/mod/semver")// ModuleJSON holds information about a module.type ModuleJSON struct {Pathstring// module pathVersionstring// module versionVersions  []string// available module versions (with -versions)Replace*ModuleJSON // replaced by this moduleTime*time.Time  // time version was createdUpdate*ModuleJSON // available update, if any (with -u)Mainboolle?Indirect  bool// is the only act depen main module?Dirstring// directory holding files for this module, if anyGoModstring// path to go.mod file used when loading this module, if anyGoVersion string// go version used in module}var modFlagRegexp = regexp.MustCompile(`-mod[ =](\w+)`)// VendorEnabled reports whether vendoring is enabled. It takes a *Runner to execute Go commands// with the supplied context.Context and Invocation. The Invocation can contain pre-defined fields,// of which only Verb and Args are modified to run the appropriate Go command.// Inspired by setDefaultBuildMod in modload/init.go VendorEnabled(ctx context.Context, inv Invocation, r *Runner) (bool, *ModuleJSON, error) {mainMod, go114, err := getMainModuleAnd114(ctx, inv, r)if err != nil {return false, nil, err}// We check the GOFLAGS to see if there is anything overridden or not.inv.Verb = "env"inv.Args = []string{"GOFLAGS"}stdout, err := r.Run(ctx, inv)if err != nil {return false, nil, err}goflags := string(bytes.TrimSpace(stdout.Bytes()))matches := modFlagRegexp.FindStringSubmatch(goflags)var modFlag stringif len(matches) != 0 {modFlag = matches[1]}// Don't override an explicit '-mod=' argument.if modFlag == "vendor" {return true, mainMod, nil} else if modFlag != "" {return false, nil, nil}if mainMod == nil || !go114 {return false, nil, nil}// Check 1.14's automatic vendor mode.if fi, err := os.Stat(filepath.Join(mainMod.Dir, "vendor")); err == nil && fi.IsDir() {if mainMod.GoVersion != "" && semver.Compare("v"+mainMod.GoVersion, "v1.14") >= 0 {// The Go version is at least 1.14, and a vendor directory exists.// Set -mod=vendor by default.return true, mainMod, nil}}return false, nil, nil}// getMainModuleAnd114 gets one of the main modules' information and whether the// go command in use is 1.14+. This is the information needed to figure outf vendoring should be enabled. getMainModuleAnd114(ctx context.Context, inv Invocation, r *Runner) (*ModuleJSON, bool, error) {const format = `{{.Path}}{{.Dir}}{{.GoMod}}{{.GoVersion}}{{range context.ReleaseTags}}{{if eq . "go1.14"}}{{.}}{{end}}{{end}}`inv.Verb = "list"inv.Args = []string{"-m", "-f", format}stdout, err := r.Run(ctx, inv)if err != nil {return nil, false, err}lines := strings.Split(stdout.String(), "\n")if len(lines) < 5 {return nil, false, fmt.Errorf("unexpected stdout: %q", stdout.String())}mod := &ModuleJSON{Path:lines[0],Dir:lines[1],GoMod:lines[2],GoVersion: lines[3],Main:true,}return mod, lines[4] == "go1.14", nil}